import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Button,
  Checkbox,
  Input,
  Modal,
  Select,
  dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft-org/linm-web-common-components';
import { masterCodePageLabels } from '../../../constants/masterCodePageLabels';
import { masterCodeService } from '../../../services/system/masterCodeService';
import {
  MASTER_CODE_FORMAT_OPTIONS,
  MASTER_CODE_SCOPE_LEGAL_ENTITY,
  MASTER_CODE_SCOPE_OPTIONS,
  SEQ_PADDING_MAX,
  SEQ_PADDING_MIN,
  buildMasterCodePreview,
  type MasterCodeLegalEntityOptionDto,
  type MasterCodeRegistrationDto,
  type UpdateMasterCodeRegistrationDto,
} from '../../../services/system/masterCodeModels';
import { useAppDispatch } from '../../../store/hooks';
import { resolveApiErrorMessage } from '../../../utils/resolveApiErrorMessage';
import styles from './MasterCodeRegistrationModal.module.css';

type FormErrors = Partial<Record<'format' | 'seqPadding' | 'legalEntityRootId', string>>;

function clampInteger(value: number, min: number, max: number): number {
  if (!Number.isFinite(value)) return min;
  const v = Math.trunc(value);
  return Math.max(min, Math.min(max, v));
}

export interface MasterCodeRegistrationModalProps {
  testIdPrefix: string;
  catalogKind: string;
  isOpen: boolean;
  onClose: () => void;
  onSaved?: () => void;
}

export const MasterCodeRegistrationModal: React.FC<MasterCodeRegistrationModalProps> = ({
  testIdPrefix,
  catalogKind,
  isOpen,
  onClose,
  onSaved,
}) => {
  const dispatch = useAppDispatch();
  const labels = masterCodePageLabels;
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: labels.leaveMessage,
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);

  const [loading, setLoading] = useState(false);
  const [registration, setRegistration] = useState<MasterCodeRegistrationDto | null>(null);
  const [legalEntityOptions, setLegalEntityOptions] = useState<MasterCodeLegalEntityOptionDto[]>([]);
  const [form, setForm] = useState<UpdateMasterCodeRegistrationDto>({
    format: 'PREFIX-NNNN',
    seqPadding: 6,
    minSequence: 1,
    maxSequence: 999999,
    scopeMode: 'Company',
    legalEntityRootId: null,
    useDepartmentPrefix: false,
  });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [saveConfirmOpen, setSaveConfirmOpen] = useState(false);

  useEffect(() => {
    if (!isOpen) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      Promise.all([
        masterCodeService.getByKind(catalogKind),
        masterCodeService.getLegalEntityOptions(),
      ])
        .then(([row, legalOptions]) => {
          if (cancelled) return;
          setRegistration(row);
          setLegalEntityOptions(legalOptions);
          setForm({
            format: row.format,
            seqPadding: row.seqPadding,
            minSequence: row.minSequence,
            maxSequence: row.maxSequence,
            scopeMode: row.scopeMode,
            legalEntityRootId: row.legalEntityRootId ?? null,
            useDepartmentPrefix: row.useDepartmentPrefix,
          });
          setErrors({});
          markClean();
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: resolveApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
            onClose();
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [isOpen, catalogKind, dispatch, labels.loadError, markClean, onClose]);

  const previewSeqPadding = useMemo(
    () => clampInteger(form.seqPadding, SEQ_PADDING_MIN, SEQ_PADDING_MAX),
    [form.seqPadding],
  );

  const previewExample = useMemo(() => {
    if (!registration) return '';
    return buildMasterCodePreview(
      registration.prefix,
      form.format,
      previewSeqPadding,
      form.minSequence,
      form.useDepartmentPrefix,
    );
  }, [registration, form.format, previewSeqPadding, form.minSequence, form.useDepartmentPrefix]);

  const closeModal = useCallback(() => {
    guardedNavigate(() => {
      markClean();
      setSaveConfirmOpen(false);
      onClose();
    });
  }, [guardedNavigate, markClean, onClose]);

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.format?.trim()) next.format = labels.formatRequired;
    if (!Number.isFinite(form.seqPadding)) {
      next.seqPadding = labels.seqPaddingRequired;
    } else {
      const v = Math.trunc(form.seqPadding);
      if (v < SEQ_PADDING_MIN || v > SEQ_PADDING_MAX) {
        next.seqPadding = labels.seqPaddingRange(SEQ_PADDING_MIN, SEQ_PADDING_MAX);
      }
    }
    if (
      form.scopeMode === MASTER_CODE_SCOPE_LEGAL_ENTITY
      && !form.legalEntityRootId
    ) {
      next.legalEntityRootId = labels.legalEntityRequired;
    }
    return next;
  };

  const handleSaveClick = () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      return;
    }
    setSaveConfirmOpen(true);
  };

  const handleConfirmSave = async () => {
    if (!registration) return;
    setSaving(true);
    try {
      await masterCodeService.update(registration.id, form);
      dispatchAppToast(dispatch, { message: labels.saveSuccess, type: 'success' });
      markClean();
      setSaveConfirmOpen(false);
      onSaved?.();
      onClose();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: resolveApiErrorMessage(err, labels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <Modal
        isOpen={isOpen}
        onClose={closeModal}
        title={labels.modalTitle}
        size="md"
        stacked
      >
        <div data-testid={`${testIdPrefix}-form`}>
          {loading ? (
            <div className={styles.loading}>
              <i className="fas fa-spinner fa-spin" /> Đang tải...
            </div>
          ) : registration ? (
            <>
              <div className={styles.formGrid}>
                <div className={styles.field}>
                  <Input label="Prefix (không đổi)" value={registration.prefix} disabled fullWidth />
                </div>
                <div className={styles.field}>
                  <Input label="Danh mục" value={registration.catalogKind} disabled fullWidth />
                </div>
                <div className={styles.field} style={{ gridColumn: '1 / -1' }}>
                  <Input label="Mô tả" value={registration.description} disabled fullWidth />
                </div>
                <div
                  className={styles.field}
                  style={{ gridColumn: '1 / -1' }}
                  data-testid={`${testIdPrefix}-field-format`}
                >
                  <Select
                    label="Định dạng"
                    required
                    value={form.format}
                    onChange={e => {
                      markDirty();
                      setErrors(prev => ({ ...prev, format: undefined }));
                      setForm(f => ({ ...f, format: e.target.value }));
                    }}
                    options={[...MASTER_CODE_FORMAT_OPTIONS]}
                    error={errors.format}
                    fullWidth
                  />
                </div>
                <div className={styles.field} data-testid={`${testIdPrefix}-field-seqPadding`}>
                  <Input
                    label="Số chữ số thứ tự"
                    type="number"
                    required
                    value={String(form.seqPadding ?? '')}
                    onChange={e => {
                      markDirty();
                      setErrors(prev => ({ ...prev, seqPadding: undefined }));
                      const raw = e.target.value;
                      const next = raw === '' ? NaN : Number(raw);
                      setForm(f => ({ ...f, seqPadding: next }));
                    }}
                    error={errors.seqPadding}
                    fullWidth
                  />
                </div>
                <div className={styles.field} data-testid={`${testIdPrefix}-field-example-preview`}>
                  <Input label="Ví dụ sau lưu" value={previewExample} disabled fullWidth />
                </div>
                <div
                  className={styles.field}
                  style={{ gridColumn: '1 / -1' }}
                  data-testid={`${testIdPrefix}-field-scopeMode`}
                >
                  <Select
                    label={labels.scopeModeLabel}
                    value={form.scopeMode}
                    onChange={e => {
                      markDirty();
                      const scopeMode = e.target.value;
                      setForm(f => ({
                        ...f,
                        scopeMode,
                        legalEntityRootId:
                          scopeMode === MASTER_CODE_SCOPE_LEGAL_ENTITY ? f.legalEntityRootId : null,
                      }));
                    }}
                    options={[...MASTER_CODE_SCOPE_OPTIONS]}
                    fullWidth
                  />
                </div>
                {form.scopeMode === MASTER_CODE_SCOPE_LEGAL_ENTITY ? (
                  <div
                    className={styles.field}
                    style={{ gridColumn: '1 / -1' }}
                    data-testid={`${testIdPrefix}-field-legalEntityRootId`}
                  >
                    <Select
                      label={labels.legalEntityLabel}
                      required
                      value={form.legalEntityRootId ?? ''}
                      onChange={e => {
                        markDirty();
                        setErrors(prev => ({ ...prev, legalEntityRootId: undefined }));
                        setForm(f => ({
                          ...f,
                          legalEntityRootId: e.target.value || null,
                        }));
                      }}
                      options={[
                        { value: '', label: 'Chọn đơn vị pháp nhân' },
                        ...legalEntityOptions.map(o => ({
                          value: o.id,
                          label: `${o.code} — ${o.name}`,
                        })),
                      ]}
                      error={errors.legalEntityRootId}
                      fullWidth
                    />
                  </div>
                ) : null}
                <div
                  className={styles.field}
                  style={{ gridColumn: '1 / -1' }}
                  data-testid={`${testIdPrefix}-field-useDepartmentPrefix`}
                >
                  <Checkbox
                    id={`${testIdPrefix}-useDepartmentPrefix`}
                    label={labels.useDepartmentPrefixLabel}
                    checked={form.useDepartmentPrefix}
                    onChange={e => {
                      markDirty();
                      setForm(f => ({ ...f, useDepartmentPrefix: e.target.checked }));
                    }}
                  />
                </div>
              </div>
              <div className={styles.footer}>
                <Button variant="secondary" onClick={closeModal} data-testid={`${testIdPrefix}-cancel-btn`}>
                  Hủy
                </Button>
                <Button
                  variant="primary"
                  onClick={handleSaveClick}
                  disabled={saving}
                  data-testid={`${testIdPrefix}-save-btn`}
                >
                  {saving ? 'Đang lưu...' : 'Lưu'}
                </Button>
              </div>
            </>
          ) : null}
        </div>
      </Modal>

      <Modal
        isOpen={saveConfirmOpen}
        onClose={() => setSaveConfirmOpen(false)}
        title={labels.confirmTitle}
        size="sm"
        stacked
        closeOnOverlayClick={false}
      >
        <p className={styles.confirmMessage}>{labels.confirmMessage}</p>
        <div className={styles.confirmActions}>
          <Button
            variant="secondary"
            onClick={() => setSaveConfirmOpen(false)}
            data-testid={`${testIdPrefix}-confirm-cancel`}
          >
            {labels.confirmCancel}
          </Button>
          <Button
            variant="primary"
            onClick={() => void handleConfirmSave()}
            disabled={saving}
            data-testid={`${testIdPrefix}-confirm-save`}
          >
            {saving ? 'Đang lưu...' : labels.confirmSave}
          </Button>
        </div>
      </Modal>

      <LeaveConfirmModal {...leaveConfirmModalProps} />
    </>
  );
};
