export function buildReportListToolbarActions(p) {
    const prefix = p.testIdPrefix;
    return [
        {
            id: 'refresh',
            placement: 'left',
            action: 'refresh',
            onClick: p.onRefresh,
            testId: `${prefix}-toolbar-refresh-btn`,
        },
        {
            id: 'viewChart',
            placement: 'left',
            action: 'viewChart',
            visible: p.canChart !== false,
            disabled: !p.onChart,
            onClick: p.onChart,
            testId: `${prefix}-toolbar-chart-btn`,
        },
        {
            id: 'print',
            placement: 'overflow',
            action: 'print',
            visible: true,
            disabled: !p.canPrint,
            onClick: p.onPrint,
            testId: `${prefix}-toolbar-print-btn`,
        },
        {
            id: 'editConfig',
            placement: 'overflow',
            action: 'editConfig',
            visible: Boolean(p.onEditConfig),
            onClick: p.onEditConfig,
            testId: `${prefix}-list-config-btn`,
        },
    ];
}
